void menu_find_provider(const Inventory &inv) {
    print_header("Find Provider by ID");
    char id[256];
    read_string("  Enter provider ID: ", id, 256);
    if (const Provider *p = inv.find_provider_by_id(id)) std::cout << "\n" << *p;
    else                                                  std::cout << "\n  Provider not found.\n";
}

void menu_add_provider(Inventory &inv) {
    print_header("Add Provider");
    Provider p;
    std::cin >> p;
    if (inv.add_provider(p))
        std::cout << "\n  Provider added successfully.\n";
    else
        std::cout << "\n  Failed: inventory is at full capacity.\n";
}

void menu_update_provider(const Inventory &inventory) {
    print_header("Update Provider");
    char id[256];
    read_string("  Enter provider ID: ", id, 256);
    Provider *p = inventory.find_provider_by_id(id);
    if (!p) { std::cout << "\n  Provider not found.\n"; return; }
    std::cout << "\n" << *p;
    std::cout << "  What to update?\n"
              << "    1. ID       4. Email\n"
              << "    2. Name     5. Address\n"
              << "    3. Phone    6. Discount\n";
    char buf[256]; double val;
    switch (read_int("  Choice: ")) {
        case 1: read_string("  New ID: ",       buf, 256); Provider::update_provider(*p, Provider::update_provider_id,       buf);  break;
        case 2: read_string("  New name: ",     buf, 256); Provider::update_provider(*p, Provider::update_provider_name,     buf);  break;
        case 3: read_string("  New phone: ",    buf, 256); Provider::update_provider(*p, Provider::update_provider_phone,    buf);  break;
        case 4: read_string("  New email: ",    buf, 256); Provider::update_provider(*p, Provider::update_provider_email,    buf);  break;
        case 5: read_string("  New address: ",  buf, 256); Provider::update_provider(*p, Provider::update_provider_address,  buf);  break;
        case 6: val = read_double("  New discount (%): "); Provider::update_provider(*p, Provider::update_provider_discount, &val); break;
        default: std::cout << "\n  Invalid choice.\n"; return;
    }
    std::cout << "\n  Updated:\n" << *p;
}

void menu_orders_by_provider(const Inventory &inv) {
    print_header("Orders by Provider");
    char id[256];
    read_string("  Enter provider ID: ", id, 256);
    int count = 0;
    Order *list = inv.get_orders_by_provider_id(id, count);
    if (count == 0) { std::cout << "\n  No orders for that provider.\n"; return; }
    std::cout << "\n  " << count << " order(s):\n\n";
    for (int i = 0; i < count; i++) std::cout << list[i];
    delete[] list;
}

void providers_menu(Inventory &inv) {
    while (true) {
        print_header("Providers");
        std::cout << "    1. View all\n"
                  << "    2. Find by ID\n"
                  << "    3. Add\n"
                  << "    4. Update\n"
                  << "    5. View orders by provider\n"
                  << "    0. Back\n";
        switch (read_int("  Choice: ")) {
            case 2: menu_find_provider(inv);      break;
            case 3: menu_add_provider(inv);       break;
            case 4: menu_update_provider(inv);    break;
            case 5: menu_orders_by_provider(inv); break;
            case 0: return;
            default: std::cout << "\n  Invalid choice.\n";
        }
    }
}

