void menu_update_order(const Inventory &inventory) {
    print_header("Update Order");
    char id[256];
    read_string("  Enter order ID: ", id, 256);
    Order *o = inventory.find_order_by_id(id);
    if (!o) { std::cout << "\n  Order not found.\n"; return; }
    std::cout << "\n" << *o;
    std::cout << "  What to update?\n"
              << "    1. ID           4. Total price\n"
              << "    2. Provider ID  5. Status\n"
              << "    3. Date\n";
    char buf[256]; double val; int st_int; Order::Status st;
    switch (read_int("  Choice: ")) {
        case 1: read_string("  New ID: ", buf, 256);              Order::update_order(*o, Order::update_order_id,          buf);  break;
        case 2: read_string("  New provider ID: ", buf, 256);     Order::update_order(*o, Order::update_order_provider_id, buf);  break;
        case 3: read_string("  New date (DD-MM-YYYY): ", buf, 256);Order::update_order(*o, Order::update_order_date,       buf);  break;
        case 4: val = read_double("  New total price: ");          Order::update_order(*o, Order::update_order_total_price, &val); break;
        case 5:
            std::cout << "  0-pending  1-delivered  2-cancelled\n";
            st_int = read_int("  New status: ");
            switch (st_int) {
                case 1: st = Order::Status::delivered; break;
                case 2: st = Order::Status::cancelled; break;
                default:st = Order::Status::pending;   break;
            }
            Order::update_order(*o, Order::update_order_status, &st);
            break;
        default: std::cout << "\n  Invalid choice.\n"; return;
    }
    std::cout << "\n  Updated:\n" << *o;
}

void menu_receive_order(Inventory &inv) {
    print_header("Receive Order");
    char id[256];
    read_string("  Enter order ID: ", id, 256);
    Order *o = inv.find_order_by_id(id);
    if (!o) { std::cout << "\n  Order not found.\n"; return; }
    std::cout << "\n" << *o;
    if (inv.receive_order(o)) {
        std::cout << "  Order received. Status: " << Order::order_status_to_string(o->get_order_status()) << "\n";
        std::cout << "  Updated quantities:\n";
        for (int i = 0; i < o->get_order_quantity_count(); i++) {
            const char *mid = o->get_order_materials_id()[i];
            if (const Material *m = inv.find_material_by_id(mid))
                std::cout << "    " << mid << " -> " << m->get_material_quantity() << " " << m->get_material_measure_unit() << "\n";
        }
        // Prompt to update new materials (those with empty name)
        for (int i = 0; i < o->get_order_materials_count(); i++) {
            const char *mid = o->get_order_materials_id()[i];
            Material *m = inv.find_material_by_id(mid);
            if (m && strcmp(m->get_material_name(), "") == 0) {
                std::cout << "\n  New material added: " << mid << "\n";
                std::cout << "  Please provide additional information:\n";
                char buf[256];
                double val;
                Material::Category cat;
                read_string("    Name: ", buf, 256);
                Material::update_material(*m, Material::update_material_name, buf);
                read_string("    Measure unit: ", buf, 256);
                Material::update_material(*m, Material::update_material_measure_unit, buf);
                val = read_double("    Critical level: ");
                Material::update_material(*m, Material::update_material_critical, &val);
                val = read_double("    Unit price: ");
                Material::update_material(*m, Material::update_material_unit_price, &val);
                std::cout << "    Category (0-wood 1-metal 2-insulation 3-finishes 4-others): ";
                switch (read_int("")) {
                    case 0: cat = Material::Category::wood; break;
                    case 1: cat = Material::Category::metal; break;
                    case 2: cat = Material::Category::insulation; break;
                    case 3: cat = Material::Category::finishes; break;
                    default: cat = Material::Category::others; break;
                }
                Material::update_material(*m, Material::update_material_category, &cat);
            }
        }
    } else {
        std::cout << "  Failed: order is not pending or insufficient capacity for new materials.\n";
    }
}

