        std::cout << "\n  Failed: inventory is at full capacity.\n";
}

void menu_update_material(const Inventory &inventory) {
    print_header("Update Material");
    char material_id[256];
    read_string("  Enter material ID: ", material_id, 256);
    Material *material = inventory.find_material_by_id(material_id);
    if (!material) { std::cout << "\n  Material not found.\n"; return; }
    std::cout << "\n" << *material;
    std::cout << "  What to update?\n"
              << "    1. ID            4. Quantity\n"
              << "    2. Name          5. Critical level\n"
              << "    3. Measure unit  6. Unit price\n"
              << "                     7. Category\n";
    char buffer[256]; double value; int category_choice; Material::Category category;
    switch (read_int("  Choice: ")) {
        case 1: read_string("  New ID: ", buffer, 256);           Material::update_material(*material, Material::update_material_id,           buffer);  break;
        case 2: read_string("  New name: ", buffer, 256);         Material::update_material(*material, Material::update_material_name,         buffer);  break;
        case 3: read_string("  New measure unit: ", buffer, 256); Material::update_material(*material, Material::update_material_measure_unit, buffer);  break;
        case 4: value = read_double("  New quantity: ");          Material::update_material(*material, Material::update_material_quantity,     &value); break;
        case 5: value = read_double("  New critical level: ");    Material::update_material(*material, Material::update_material_critical,     &value); break;
        case 6: value = read_double("  New unit price: ");        Material::update_material(*material, Material::update_material_unit_price,   &value); break;
        case 7:
            std::cout << "  0-wood  1-metal  2-insulation  3-finishes  4-others\n";
            category_choice = read_int("  New category: ");
            switch (category_choice) {
                case 0: category = Material::Category::wood;       break;
                case 1: category = Material::Category::metal;      break;
                case 2: category = Material::Category::insulation; break;
                case 3: category = Material::Category::finishes;   break;
                default:category = Material::Category::others;     break;
            }
            Material::update_material(*material, Material::update_material_category, &category);
            break;
        default: std::cout << "\n  Invalid choice.\n"; return;
    }
    std::cout << "\n  Updated:\n" << *material;
}

void menu_consume_material(const Inventory &inventory) {
    print_header("Consume Material");
    char material_id[256];
    read_string("  Enter material ID: ", material_id, 256);
    Material *material = inventory.find_material_by_id(material_id);
    if (!material) { std::cout << "\n  Material not found.\n"; return; }
    std::cout << "\n" << *material;
    double quantity = read_double("  Quantity to consume: ");
    if (inventory.consume_material(material_id, quantity)) {
        std::cout << "\n  Consumed successfully.\n";
        std::cout << "  New quantity: " << inventory.find_material_by_id(material_id)->get_material_quantity()
                  << " " << material->get_material_measure_unit() << "\n";
    } else {
        std::cout << "\n  Failed: insufficient quantity or invalid amount.\n";
    }
}

void menu_sort_materials(const Inventory &inventory) {
    print_header("Sort Materials");
    std::cout << "    1. By name (ascending)\n"
              << "    2. By name (descending)\n"
              << "    3. By quantity (ascending)\n"
              << "    4. By quantity (descending)\n";
    switch (read_int("  Choice: ")) {
        case 1: inventory.sort_materials_by_name_ascending();      break;
        case 2: inventory.sort_materials_by_name_descending();     break;
        case 3: inventory.sort_materials_by_quantity_ascending();  break;
        case 4: inventory.sort_materials_by_quantity_descending(); break;
        default: std::cout << "\n  Invalid choice.\n"; return;
    }
    std::cout << "\n  Sorted:\n";
    for (int index = 0; index < inventory.get_inventory_materials_count(); index++)
        std::cout << inventory.get_inventory_materials()[index];
}

void menu_critical_materials(const Inventory &inventory) {
    print_header("Critical Materials");
    int critical_count = 0;
    Material *critical_list = inventory.get_critical_materials(critical_count);
    if (critical_count == 0) { std::cout << "  No materials at or below critical level.\n"; return; }
    std::cout << "  " << critical_count << " critical material(s):\n\n";
    for (int index = 0; index < critical_count; index++) std::cout << critical_list[index];
    delete[] critical_list;
}

void menu_materials_by_category(const Inventory &inventory) {
    print_header("Materials by Category");
    std::cout << "  0-wood  1-metal  2-insulation  3-finishes  4-others\n";
    int category_choice = read_int("  Category: ");
    Material::Category category;
    switch (category_choice) {
        case 0: category = Material::Category::wood;       break;
        case 1: category = Material::Category::metal;      break;
        case 2: category = Material::Category::insulation; break;
        case 3: category = Material::Category::finishes;   break;
        default:category = Material::Category::others;     break;
    }
    int category_count = 0;
    Material *category_list = inventory.get_materials_by_category(category, category_count);
    if (category_count == 0) { std::cout << "\n  No materials in that category.\n"; return; }
    std::cout << "\n  " << category_count << " material(s):\n\n";
    for (int index = 0; index < category_count; index++) std::cout << category_list[index];
    delete[] category_list;
}

void materials_menu(Inventory &inventory) {
    while (true) {
        print_header("Materials");
        std::cout << "    1. View all           5. Consume\n"
                  << "    2. Find by ID         6. Sort\n"
                  << "    3. Add                7. View critical\n"
                  << "    4. Update             8. View by category\n"
                  << "    0. Back\n";
        switch (read_int("  Choice: ")) {
            case 2: menu_find_material(inventory);         break;
            case 3: menu_add_material(inventory);       break;
            case 4: menu_update_material(inventory);       break;
            case 5: menu_consume_material(inventory);      break;
            case 6: menu_sort_materials(inventory);        break;
            case 7: menu_critical_materials(inventory);    break;
            case 8: menu_materials_by_category(inventory); break;
            case 0: return;
            default: std::cout << "\n  Invalid choice.\n";
        }
    }
}

