//  Main menu
// ─────────────────────────────────────────────

void main_menu(Inventory &inventory) {
    print_header("Main Menu");
    std::cout << "    1. Materials\n"
              << "    2. Providers\n"
              << "    3. Orders\n"
              << "    0. Exit\n";
    switch (read_int("  Choice: ")) {
        case 1: materials_menu(inventory); break;
        case 2: providers_menu(inventory); break;
        case 3: orders_menu(inventory);    break;
        case 0: std::cout << "  Goodbye!\n"; exit(0);
        default: std::cout << "\n  Invalid choice.\n";
    }
}

int main() {
    Inventory inventory;
    seed_inventory(inventory);
    while (true) main_menu(inventory);
    return 0;
}
